// Route the incoming query type to a parameter set for the Postgres node
const body = $input.first().json.body || {};
const queryType = body.query_type || 'deal_health_all';
const dealId = body.deal_id || null;

// Build SQL based on query_type
let sql;

switch (queryType) {
  case 'deal_health_single':
    if (!dealId) throw new Error('deal_health_single requires deal_id');
    sql = `SELECT d.deal_id, d.company_name, d.salesforce_stage, d.deal_stage,
             d.deal_value_usd, d.close_date, d.forecast_category, d.deal_owner,
             d.is_active, d.updated_at,
             dh.pain_score, dh.power_score, dh.vision_score, dh.value_score,
             dh.change_score, dh.control_score, dh.p2v2c2_total,
             dh.critical_activity_stage, dh.champion_name, dh.champion_title,
             dh.executive_sponsor_name, dh.executive_sponsor_title,
             dh.pe_sponsor_score, dh.pe_sponsor_justification,
             dh.dap_exists, dh.dap_agreed, dh.dap_status,
             dh.dap_milestones_complete, dh.dap_has_14_day_gap,
             dh.dap_next_milestone, dh.dap_next_milestone_date, dh.dap_summary,
             dh.current_state_org, dh.current_state_activities, dh.current_state_technology,
             dh.future_state_org, dh.future_state_activities, dh.future_state_technology,
             dh.key_stakeholder_success_criteria, dh.risks,
             dh.next_step, dh.next_step_date,
             dh.call_summary, dh.highlights,
             dh.action_items_prospect, dh.action_items_internal, dh.internal_actions,
             dh.services_narrative, dh.general_narrative, dh.internal_team_update,
             dh.trend_direction, dh.score_vs_previous, dh.scored_at
           FROM deals d
           LEFT JOIN LATERAL (
             SELECT * FROM deal_health WHERE deal_id = d.deal_id ORDER BY scored_at DESC LIMIT 1
           ) dh ON true
           WHERE d.deal_id = '${dealId}'
           LIMIT 1`;
    break;

  case 'deal_health_all':
    sql = `SELECT d.deal_id, d.company_name, d.salesforce_stage, d.deal_stage,
             d.deal_value_usd, d.close_date, d.forecast_category, d.is_active,
             dh.pain_score, dh.power_score, dh.vision_score, dh.value_score,
             dh.change_score, dh.control_score, dh.p2v2c2_total,
             dh.critical_activity_stage, dh.champion_name, dh.executive_sponsor_name,
             dh.next_step, dh.next_step_date, dh.trend_direction,
             dh.score_vs_previous, dh.scored_at
           FROM deals d
           LEFT JOIN LATERAL (
             SELECT * FROM deal_health WHERE deal_id = d.deal_id ORDER BY scored_at DESC LIMIT 1
           ) dh ON true
           WHERE d.is_active = true
           ORDER BY dh.p2v2c2_total DESC NULLS LAST`;
    break;

  case 'attribution_queue':
    sql = `SELECT id, sender_email, sender_domain, subject, email_date,
             ai_guess_deal_id, ai_guess_company, ai_confidence, doc_type, queued_at
           FROM attribution_queue
           WHERE resolution = 'pending'
           ORDER BY queued_at ASC
           LIMIT 20`;
    break;

  case 'outputs_log':
    if (!dealId) throw new Error('outputs_log requires deal_id');
    sql = `SELECT output_type, recipient_email, recipient_name, subject,
             content_summary, sent_at, triggered_by
           FROM outputs_log
           WHERE deal_id = '${dealId}'
           ORDER BY sent_at DESC
           LIMIT 20`;
    break;

  case 'ingestion_log':
    if (!dealId) throw new Error('ingestion_log requires deal_id');
    sql = `SELECT doc_type, subject, sender_email, chunk_count, ingested_at
           FROM ingestion_log
           WHERE deal_id = '${dealId}'
           ORDER BY ingested_at DESC
           LIMIT 20`;
    break;

  case 'pipeline_summary':
    sql = `SELECT d.deal_stage, d.forecast_category,
             COUNT(*) AS deal_count,
             SUM(d.deal_value_usd) AS total_value,
             ROUND(AVG(dh.p2v2c2_total), 1) AS avg_p2v2c2,
             COUNT(CASE WHEN dh.trend_direction = 'declining' THEN 1 END) AS declining_deals
           FROM deals d
           LEFT JOIN LATERAL (
             SELECT * FROM deal_health WHERE deal_id = d.deal_id ORDER BY scored_at DESC LIMIT 1
           ) dh ON true
           WHERE d.is_active = true
           GROUP BY d.deal_stage, d.forecast_category
           ORDER BY d.deal_stage`;
    break;

  case 'confirm_attribution':
    const msgId = body.message_id || null;
    const resolvedDealId = body.resolved_deal_id || null;
    const resolution = body.resolution || 'confirmed';
    if (!msgId) throw new Error('confirm_attribution requires message_id');
    sql = `UPDATE attribution_queue
           SET resolution = '${resolution}',
               resolved_deal_id = ${resolvedDealId ? `'${resolvedDealId}'` : 'NULL'},
               resolved_at = NOW()
           WHERE message_id = '${msgId}'
           RETURNING id, message_id, resolution, resolved_deal_id`;
    break;

  default:
    throw new Error(`Unknown query_type: ${queryType}`);
}

return [{ json: { query_type: queryType, sql, deal_id: dealId } }];

// Collect all rows and return as a clean JSON array
const rows = $input.all().map(item => item.json);
const queryType = $('Code: Route Query').first().json.query_type;

return [{
  json: {
    query_type: queryType,
    row_count: rows.length,
    rows
  }
}];
